mapper.select:
SELECT *,C.name groupName FROM `md_user_channel` A LEFT JOIN `md_user_channel_related` B ON A.`id`=B.`channel_id` AND A.app_id=B.app_id AND A.tenant_id=B.tenant_id LEFT JOIN `md_user_channel_group` C ON A.`group_id`=C.`id` WHERE A.app_id=#{appId} AND A.tenant_id=#{tenantId} AND B.`user_id`=#{userId}
AND A.name like concat('%',#{name},'%')
GROUP BY A.id
